module multi_16bit(
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);
//   <reg id="i" value="0">Shift count register.</reg>
//   <reg id="done_r" value="0">Multiplication completion flag.</reg>
//   <reg id="carry" value="0">Carry bit for addition.</reg>
//   <reg id="areg" width_description="[15:0]">Multiplicand register.</reg>
//   <reg id="breg" width_description="[15:0]">Multiplier register.</reg>
//   <reg id="yout_r" width_description="[31:0]">Product register.</reg>
    reg [4:0] i;
    reg done_r;
    reg carry;
    reg [15:0] areg;
    reg [15:0] breg;
    reg [31:0] yout_r;
    //   <p>Initialize the shift count register (i) to 0.</p>
    //   <p>On every positive edge of the clock signal (clk) or the falling edge of the reset signal (rst_n), the shift count register (i) is updated.</p>
    //   <p>If the reset signal (rst_n) is low, indicating a reset condition, the shift count register (i) is set to 0.</p>
    //   <p>If the start signal is active (start) and the shift count register (i) is less than 17, the shift count register (i) increments by 1.</p>
    //   <p>If the start signal is inactive (!start), the shift count register (i) is reset to 0.</p>
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) i<=0;
        else if (start && i<17) i<=i+1;
        else if (!start) i<=0;
    end 
    //   <p>On every positive edge of the clock signal (clk) or the falling edge of the reset signal (rst_n), the multiplication completion flag (done_r) is updated.</p>
    //   <p>If the reset signal (rst_n) is low, the multiplication completion flag (done_r) is set to 0.</p>
    //   <p>If the shift count register (i) is equal to 16, indicating the completion of the multiplication operation, the multiplication completion flag (done_r) is set to 1.</p>
    //   <p>If the shift count register (i) is equal to 17, the multiplication completion flag (done_r) is reset to 0.</p>
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) done_r<=0;
        else if (i==16) done_r<=1;
        else if (i==17) done_r<=0;
    end 
    //   <p>On every positive edge of the clock signal (clk) or the falling edge of the reset signal (rst_n), the module performs the shift and accumulate operation.</p>
    //   <p>If the reset signal (rst_n) is low, indicating a reset condition, the multiplicand register (areg), multiplier register (breg), and product register (yout_r) are reset to 0.</p>
    //   <p>If the start signal is active (start), the module starts the multiplication operation.</p>
    //   <p>When the shift count register (i) is 0, the multiplicand (ain) and multiplier (bin) are stored in the respective registers (areg and breg).</p>
    //   <p>For shift counts greater than 0 and less than 17, if the bit at position i-1 in the multiplicand register (areg) is high, the product register (yout_r) accumulates the shifted value of the multiplier register (breg) by shifting it left by i-1 positions and appending zeros at the least significant bit positions.</p>
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            areg<=0;
            breg<=0;
            yout_r<=0;
        end
        else if (start) begin
            if (i==0) begin
                areg<=ain;
                breg<=bin;
            end
            else if (i>0 && i<17) begin
                if (areg[i-1]) begin
                    yout_r<=yout_r+(breg<<(i-1)|{16'b0});
                end
            end
        end
    end 
    assign done=done_r;
    assign yout=yout_r;
endmodule
